/**
 * Pure prompt-classification heuristics for the model-router extension.
 * Extracted here so they can be imported by both the extension and tests
 * without pulling in the Copilot SDK or any top-level await.
 */

export const EXPLICIT_REVIEW_KEYWORDS = [
  "review",
  "code review",
  "review this",
  "review the code",
  "review my code",
  "audit",
  "approval readiness",
  "approval readiness checks",
  "approve this",
  "pr review",
  // Bug finding, regression hunting, and approval-readiness are explicit review asks per SKILL.md
  "find bugs",
  "bug finding",
  "regression hunting",
  "regression hunt",
  "find regressions",
];

export const PLAN_KEYWORDS = [
  "plan",
  "design",
  "architecture",
  "architect",
  "proposal",
  "strategy",
  "approach",
];

export const DEBUG_KEYWORDS = [
  "debug",
  "fix",
  "failure",
  "failing",
  "error",
  "crash",
  "root cause",
  "broken",
  "investigate",
];

export const IMPLEMENT_KEYWORDS = [
  "implement",
  "build",
  "create",
  "write",
  "refactor",
  "add",
  "change",
  "update",
  "edit",
  "enhance",
  "modify",
  "adjust",
  "improve",
  "fix the code",
  "fix the formatting",
  "fix the logic",
];

export const LIGHT_KEYWORDS = [
  "explain",
  "summarize",
  "what is",
  "where is",
  "find",
  "list",
  "show",
  "search",
];

export const TOOL_KEYWORDS = [
  "bash",
  "curl",
  "execute",
  "run",
  "tool",
  "api",
  "function",
  "call",
  "invoke",
  "script",
  "command",
  "shell",
  "http",
  "request",
  "endpoint",
