200. // Simple word-level similarity detection (0-1, where 1 is identical)
201. function calculateSimilarity(text1, text2) {
202.   const words1 = new Set(normalizePrompt(text1).split(/\s+/).filter(w => w.length > 3));
203.   const words2 = new Set(normalizePrompt(text2).split(/\s+/).filter(w => w.length > 3));
204.   
205.   if (words1.size === 0 || words2.size === 0) return 0;
206.   
207.   const intersection = [...words1].filter(w => words2.has(w)).length;
208.   const union = new Set([...words1, ...words2]).size;
209.   
210.   return union > 0 ? intersection / union : 0;
211. }
