213. // Detect if agent message shows signs of confusion or looping
214. function detectConfusionSignals(message) {
215.   const text = normalizePrompt(message);
216.   const signals = [];
217.   
218.   // Signal 1: Agent acknowledging it's confused or stuck
219.   const confusedPhrases = [
220.     "i'm not sure",
221.     "i'm confused",
222.     "unclear",
223.     "not clear",
224.     "i don't",
225.     "cannot proceed",
226.     "stuck",
227.     "unable to",
228.     "let me try",
229.     "let me re-attempt",
230.   ];
231.   if (includesAny(text, confusedPhrases)) {
232.     signals.push("agent-confusion-acknowledgment");
233.   }
234.   
235.   // Signal 2: Very short responses (often indicates agent giving up or looping)
236.   if (text.split(/\s+/).length < 10) {
237.     signals.push("very-short-response");
238.   }
239.   
240.   // Signal 3: Repetitive question asking (agent asking for clarification repeatedly)
241.   if (includesAny(text, ["can you", "could you", "would you", "please", "more details", "clarify"])) {
242.     const askingCount = (text.match(/\?/g) || []).length;
243.     if (askingCount > 2) {
244.       signals.push("repetitive-asking");
245.     }
246.   }
247.   
248.   // Signal 4: Self-contradictory statements
249.   if (text.includes("but earlier") || text.includes("wait,") || text.includes("i was wrong")) {
250.     signals.push("self-contradiction");
251.   }
252.   
253.   return signals;
254. }
