256. // Check if recent messages suggest a loop
257. function detectLoopingBehavior() {
258.   if (confusionMetrics.recentMessages.length < 3) return false;
259.   
260.   let similarPairs = 0;
261.   for (let i = confusionMetrics.recentMessages.length - 1; i > 0; i--) {
262.     const similarity = calculateSimilarity(
