/**
 * Regression tests for prompt-classification heuristics.
 * Uses only Node built-ins: node:test and node:assert.
 * Run with: node --test classify.test.mjs
 */

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import {
  matchesPattern,
  isExplicitReviewRequest,
  isToolHeavy,
  isComplexOrchestration,
  classifyPrompt,
  normalizePrompt,
} from "./classify.mjs";

// ---------------------------------------------------------------------------
// matchesPattern – word-boundary protection
// ---------------------------------------------------------------------------

describe("matchesPattern – word-boundary safety", () => {
  it("matches standalone 'fix' but not 'prefix'", () => {
    assert.equal(matchesPattern("fix the bug", "fix"), true);
    assert.equal(matchesPattern("there is a prefix", "fix"), false);
  });

  it("matches standalone 'call' but not 'callback'", () => {
    assert.equal(matchesPattern("call the api", "call"), true);
    assert.equal(matchesPattern("use a callback", "call"), false);
  });

  it("matches standalone 'change' but not 'exchange'", () => {
    assert.equal(matchesPattern("change the config", "change"), true);
    assert.equal(matchesPattern("exchange data", "change"), false);
  });

  it("multi-word phrase uses substring matching", () => {
    assert.equal(matchesPattern("run parallel agents now", "parallel agents"), true);
    assert.equal(matchesPattern("no match here", "parallel agents"), false);
  });

  it("is case-sensitive after normalisation (caller must lowercase)", () => {
    // matchesPattern itself is not case-insensitive; callers normalise first
    assert.equal(matchesPattern("Fix The Bug", "fix"), false);
    assert.equal(matchesPattern(normalizePrompt("Fix The Bug"), "fix"), true);
  });
});

// ---------------------------------------------------------------------------
// isExplicitReviewRequest
// ---------------------------------------------------------------------------

describe("isExplicitReviewRequest – positive cases", () => {
  const positives = [
    "please review this PR",
    "can you do a code review",
    "review the code in src/auth.ts",
    "review my code and tell me what's wrong",
    "audit the security configuration",
    "check approval readiness",
    "approval readiness checks before we ship",
    "approve this PR",
    "pr review checklist",
    "find bugs in the login flow",
    "I need bug finding on this module",
    "regression hunting after the deploy",
    "regression hunt for the payment service",
    "find regressions introduced in v2",
  ];

  for (const prompt of positives) {
    it(`detects review intent: "${prompt}"`, () => {
      assert.equal(isExplicitReviewRequest(normalizePrompt(prompt)), true);
    });
  }
});

describe("isExplicitReviewRequest – negative cases (must NOT fire)", () => {
  const negatives = [
    "implement a new feature",
    "build a CI pipeline",
    "explain how the auth module works",
    "what is the difference between PUT and PATCH",
    "refactor the database layer",
    "debug the failing test",
    "write unit tests for the parser",
    // 'fix' alone is a debug keyword, not a review keyword
    "fix the null-pointer error",
  ];

  for (const prompt of negatives) {
    it(`does NOT detect review intent: "${prompt}"`, () => {
      assert.equal(isExplicitReviewRequest(normalizePrompt(prompt)), false);
    });
  }
});

// ---------------------------------------------------------------------------
// isToolHeavy
// ---------------------------------------------------------------------------

describe("isToolHeavy – positive cases", () => {
  const positives = [
    "run a bash script to deploy",
    "use curl to hit the API",
    "execute the migration",
    "call the GitHub API",
    "invoke the shell command",
    "write a script that makes http requests",
    "set up an agent to monitor the endpoint",
  ];

  for (const prompt of positives) {
    it(`detects tool-heavy intent: "${prompt}"`, () => {
      assert.equal(isToolHeavy(normalizePrompt(prompt)), true);
    });
  }
});

describe("isToolHeavy – negative cases", () => {
  const negatives = [
    "explain the data model",
    "summarize the last three commits",
    "what is the architecture of this service",
    "design a new authentication flow",
  ];

  for (const prompt of negatives) {
    it(`does NOT detect tool-heavy intent: "${prompt}"`, () => {
      assert.equal(isToolHeavy(normalizePrompt(prompt)), false);
    });
  }
});

// ---------------------------------------------------------------------------
// isComplexOrchestration
// ---------------------------------------------------------------------------

describe("isComplexOrchestration – positive cases", () => {
  const positives = [
    "run parallel agents to process each shard",
    "use multiple agents to crawl the repos",
    "build a multi-agent workflow",
    "orchestrate the data pipeline",
    "set up orchestration for the CI jobs",
    "run parallel tools across environments",
    "create a tool chain for the release process",
    "implement chained tools for the ingestion flow",
  ];

  for (const prompt of positives) {
    it(`detects orchestration: "${prompt}"`, () => {
      assert.equal(isComplexOrchestration(normalizePrompt(prompt)), true);
    });
  }
});

describe("isComplexOrchestration – negative cases", () => {
  const negatives = [
    "run the tests",
    "use an agent to summarize the log",
    "build a simple API",
    "write a bash script",
    "implement a feature using the tool",
  ];

  for (const prompt of negatives) {
    it(`does NOT detect orchestration: "${prompt}"`, () => {
      assert.equal(isComplexOrchestration(normalizePrompt(prompt)), false);
    });
  }
});

// ---------------------------------------------------------------------------
// classifyPrompt – explicit review detection → tier: "reasoning"
// ---------------------------------------------------------------------------

describe("classifyPrompt – explicit review → reasoning tier", () => {
  it("short review phrase routes to reasoning", () => {
    const result = classifyPrompt("review this PR");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });

  it("audit request routes to reasoning", () => {
    const result = classifyPrompt("audit the security configuration");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });

  it("find bugs routes to reasoning", () => {
    const result = classifyPrompt("find bugs in the checkout module");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });

  it("regression hunt routes to reasoning", () => {
    const result = classifyPrompt("regression hunt after the last deploy");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });

  it("review takes priority over implement keywords in same prompt", () => {
    // 'create' is an implement keyword, but 'review' should win
    const result = classifyPrompt("review and create a summary of the changes");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });
});

// ---------------------------------------------------------------------------
// classifyPrompt – tool-heavy implementation → builder tier (at minimum)
// ---------------------------------------------------------------------------

describe("classifyPrompt – tool-heavy implementation → builder tier", () => {
  it("simple implement + bash keyword → builder, toolHeavy: true", () => {
    const result = classifyPrompt("write a bash script that backs up the database");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.equal(result.toolHeavy, true);
  });

  it("build + curl keyword → builder, toolHeavy: true", () => {
    const result = classifyPrompt("build a curl command to poll the status endpoint");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.equal(result.toolHeavy, true);
  });

  it("add + API call → builder, toolHeavy: true", () => {
    const result = classifyPrompt("add a function that calls the GitHub API");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.equal(result.toolHeavy, true);
  });

  it("implement without tool keywords → builder, toolHeavy: false", () => {
    const result = classifyPrompt("implement a user registration form");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.equal(result.toolHeavy, false);
  });

  it("general prompt with tool keyword and complexity ≥ 1 → builder", () => {
    // No implement/review keyword, but has 'shell' + enough complexity words
    const result = classifyPrompt(
      "carefully run shell commands to set up the environment across all nodes"
    );
    // 'run' matches DEBUG_KEYWORDS via 'fix'? No – 'run' is a TOOL keyword.
    // 'carefully' adds complexity +2, so complexity >= 2 → general builder is >=2
    assert.equal(result.tier, "builder");
  });
});

// ---------------------------------------------------------------------------
// classifyPrompt – orchestration escalation → reasoning tier
// ---------------------------------------------------------------------------

describe("classifyPrompt – orchestration escalation → reasoning tier", () => {
  it("implement + orchestrate → reasoning", () => {
    const result = classifyPrompt("implement a system that orchestrates the data pipeline");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning");
  });

  it("build + parallel agents → reasoning", () => {
    const result = classifyPrompt("build a workflow that runs parallel agents on each shard");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning");
  });

  it("create + multi-agent → reasoning", () => {
    const result = classifyPrompt("create a multi-agent system for distributed processing");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning");
  });

  it("general + orchestration → reasoning (no implement keyword)", () => {
    const result = classifyPrompt("set up tool chain for the release workflow");
    assert.equal(result.tier, "reasoning");
  });

  it("orchestration escalation beats tool-heavy bump to builder", () => {
    const result = classifyPrompt(
      "write a bash script using chained tools to deploy across regions"
    );
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning");
    assert.equal(result.toolHeavy, true);
  });
});

// ---------------------------------------------------------------------------
// classifyPrompt – lightweight / economy tier guard
// ---------------------------------------------------------------------------

describe("classifyPrompt – lightweight prompts stay in economy tier", () => {
  it("simple question → lightweight, economy", () => {
    const result = classifyPrompt("what is a closure");
    assert.equal(result.kind, "lightweight");
    assert.equal(result.tier, "economy");
  });

  it("find/list/show → lightweight, economy", () => {
    const result = classifyPrompt("list all the test files");
    assert.equal(result.kind, "lightweight");
    assert.equal(result.tier, "economy");
  });

  it("explain → lightweight, economy", () => {
    const result = classifyPrompt("explain the auth middleware");
    assert.equal(result.kind, "lightweight");
    assert.equal(result.tier, "economy");
  });
});

